 1	import { Rule } from '@openshift-console/dynamic-plugin-sdk';
 2	import {
 3	  Alert,
 4	  AlertActionCloseButton,
 5	  AlertActionLink,
 6	  Text,
 7	  TextContent,
 8	  TextVariants
 9	} from '@patternfly/react-core';
10	import * as React from 'react';
11	import { useTranslation } from 'react-i18next';
12	import { useNavigate } from '../../utils/url';
13	import './banner.css';
14	
15	export interface AlertBannerProps {
16	  rule: Rule;
17	  onDelete: () => void;
18	}
19	
20	export const AlertBanner: React.FC<AlertBannerProps> = ({ rule, onDelete }) => {
21	  const { t } = useTranslation('plugin__netobserv-plugin');
22	  const navigate = useNavigate();
23	
24	  const routeAlert = () => {
25	    let path = `/monitoring/alerts/${rule.id}`;
26	    path += `?alertname=${rule.name}&app=${rule.labels.app}&severity=${rule.labels.severity}`;
27	    navigate(path);
28	  };
29	  const routeDashboard = () => {
30	    const path = `/monitoring/dashboards/grafana-dashboard-netobserv-health`;
31	    navigate(path);
32	  };
33	  return (
34	    <div className="netobserv-alert">
35	      <Alert
36	        title={rule.name}
37	        isInline={true}
38	        variant="danger"
39	        actionClose={<AlertActionCloseButton onClose={onDelete} />}
40	        actionLinks={
41	          <React.Fragment>
42	            <AlertActionLink onClick={routeAlert}>{t('View alert details')}</AlertActionLink>
43	            <AlertActionLink onClick={routeDashboard}>{t('View health dashboard')}</AlertActionLink>
44	          </React.Fragment>
45	        }
46	      >
47	        <TextContent>
48	          <Text component={TextVariants.p}>{!!rule.annotations.description ? rule.annotations.description : ''}</Text>
49	        </TextContent>
50	      </Alert>
51	    </div>
52	  );
53	};
54	
55	export default AlertBanner;

